function isValidPath(s: unknown): s is string {
  if (typeof s !== 'string' || s.length === 0) return false;
  if (s.startsWith('{') || s.startsWith('[') || s.includes('\0')) return false;
  return true;
}

const STRING_FIELDS = new Set([
  'command', 'file_path', 'content', 'old_string', 'new_string',
  'pattern', 'description', 'prompt', 'skill', 'args', 'path',
]);

function normalizeInput(input: Record<string, unknown>): Record<string, unknown> {
  if (!input.tool_input && input.toolInput) {
    input.tool_input = input.toolInput;
  }
  if (!input.tool_input) {
    input.tool_input = {};
  }

  const toolInput = input.tool_input as Record<string, unknown>;
  for (const [key, val] of Object.entries(toolInput)) {
    if (STRING_FIELDS.has(key)) continue;
    if (typeof val === 'string' && (val.startsWith('[') || val.startsWith('{'))) {
      try {
        const parsed = JSON.parse(val);
        if (typeof parsed === 'object' && parsed !== null) {
          toolInput[key] = parsed;
        }
      } catch {
        // Not valid JSON — leave as-is
      }
    }
  }

  input.tool_name = input.tool_name || input.toolName || '';
  input.session_id = input.session_id || input.sessionId || '';
  input.hook_event = input.hook_event || input.hook_event_name || '';

  const candidates = [input.project_dir, input.projectDir, input.cwd];
  input.project_dir = candidates.find(isValidPath) || '.';

  if ((input as Record<string, unknown>).agent_type && !toolInput.subagent_type) {
    toolInput.subagent_type = (input as Record<string, unknown>).agent_type;
  }
  if ((input as Record<string, unknown>).agent_id && !toolInput.agent_id) {
    toolInput.agent_id = (input as Record<string, unknown>).agent_id;
  }
  return input;
}

