describe('isValidPath', () => {
  it('accepts normal filesystem paths', () => {
    expect(isValidPath('/Users/test/project')).toBe(true);
    expect(isValidPath('/tmp/foo.ts')).toBe(true);
    expect(isValidPath('.')).toBe(true);
    expect(isValidPath('relative/path')).toBe(true);
  });

  it('rejects JSON strings (#1250 regression)', () => {
    expect(isValidPath('{"continue":true}')).toBe(false);
    expect(isValidPath('[1,2,3]')).toBe(false);
  });

  it('rejects null bytes', () => {
    expect(isValidPath('/tmp/\0malicious')).toBe(false);
  });

  it('rejects empty strings', () => {
    expect(isValidPath('')).toBe(false);
  });

  it('rejects non-string values', () => {
    expect(isValidPath(null)).toBe(false);
    expect(isValidPath(undefined)).toBe(false);
    expect(isValidPath(42)).toBe(false);
    expect(isValidPath({})).toBe(false);
  });
});

